 /// A trait for reading the hash of a node into a given Write impl, given the pointer to a node in
 /// a trie.
 pub trait NodeHashReader {
     fn read_node_hash_bytes<W: Write>(&mut self, ptr: &TriePtr, w: &mut W) -> Result<(), Error>;
 }

+const EMPTY_BLOCK_HASH_BYTES: [u8; BLOCK_HEADER_HASH_ENCODED_SIZE] =
+    [0; BLOCK_HEADER_HASH_ENCODED_SIZE];
+
+/// Feed a node's consensus bytes directly into a trie hasher.
+///
+/// This mirrors `TrieNode::write_consensus_bytes`, but avoids the `std::io::Write` adapter on the
+/// deferred seal hot path. The byte order is consensus-critical: node id, pointer consensus bytes,
+/// path length, then path bytes.
+pub(crate) fn update_nodetype_consensus_hash<M: BlockMap>(
+    node: &TrieNodeType,
+    block_map: &mut M,
+    hasher: &mut TrieHasher,
+) -> Result<(), Error> {
+    hasher.update([node.id()]);
+
+    for ptr in node.ptrs() {
+        hasher.update([ptr.id(), ptr.chr()]);
+
+        if is_backptr(ptr.id()) {
+            hasher.update(
+                block_map
+                    .get_block_hash_caching(ptr.back_block())
+                    .expect("Block identifier {} refered to an unknown block. Consensus failure.")
+                    .as_bytes(),
+            );
+        } else {
+            hasher.update(EMPTY_BLOCK_HASH_BYTES);
+        }
+    }
+
+    let path = node.path_bytes();
+    if path.len() > 32 {
+        return Err(Error::CorruptionError(
+            "Invali path -- greater than 32 bytes".into(),
+        ));
+    }
+    hasher.update([path.len() as u8]);
+    hasher.update(path);
+
+    Ok(())
+}
