         let mut frontier: VecDeque<u32> = VecDeque::new();

         let mut node_data = vec![];
         let mut offsets = vec![];

         let start = TriePtr::new(TrieNodeID::Node256 as u8, 0, 0).ptr();
         frontier.push_back(start);

